var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐! 아가씨들! 그쪽 상황은 어때?","JPN":"おい、嬢ちゃんたち！　そっちの状況はどうだ？","ENG":"Hey! Ladies! How's it going over there?","TWN":"喂！小姐們！你們那裡情況怎麼樣啦？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"치즈케이크에 커피 한 잔 할 여유는 있나?!","JPN":"チーズケーキとコーヒー1杯くらい楽しむ余裕はあるか！？","ENG":"Enjoying a little tea time, are you?","TWN":"有空喝杯咖啡搭配起司蛋糕嗎？！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"가족이랑 사촌들 안부는 다 물었고?","JPN":"家族や親戚の安否も確認できたか？","ENG":"Done with your chitchat?","TWN":"已經跟家人和表兄弟姊妹們都問好了嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"여긴...... 젠장, 피해!","JPN":"ここは……ちくしょう、逃げろ！","ENG":"As for the situation here... Damn it! Watch out!","TWN":"這裡……該死，出現傷者了！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"으아아! 내 등에 불 붙었어!","JPN":"うわあ！　俺の背中に火が点いたよ！","ENG":"Aaah! My back is on fire!","TWN":"啊啊啊！我的背後著火啦！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"비켜! 내가 꺼 줄게!","JPN":"どけ！　俺が消してやる！","ENG":"Get down! I’ll snuff it out for you!","TWN":"閃開！我來幫他滅火！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"야! 그렇다고 몸으로 덮치면 어떡해!","JPN":"おい！　だからって、いきなり覆い被さってどうする！","ENG":"Hey! That doesn’t mean you should tackle him!","TWN":"喂！就算這樣，你也用不著壓在他身上啊！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"제리가 숨을 못 쉬는 것 같은데?!","JPN":"ジェリーが息してないみたいだぞ！？","ENG":"I don’t think Jerry's breathing anymore!","TWN":"傑瑞好像沒有呼吸了耶？！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"사장님! 해외출장이라고 해서 따라왔는데 이게 뭐에요!","JPN":"社長！　海外出張だと言うからついて来たのに、これはどういうことですか！","ENG":"Boss! This wasn’t what I had in mind when you said “international business trip!”","TWN":"老闆！你說要海外出差我才跟來的，但現在這算什麼啊！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"나 디트로이트로 돌아갈래!","JPN":"私、デトロイトに帰る！","ENG":"I’m gonna go back to Detroit!","TWN":"我要回底特律！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"시끄러워! 혼자 해외여행 가는 꼴은 못 본다고 억지로 따라온 건 너잖아!","JPN":"やかましい！　1人で海外旅行はずるいって、お前が無理やりついてきたんだろ！","ENG":"Oh, shut it. You're the one who tagged along because you were jealous of me “traveling” abroad!","TWN":"吵死了！明明是妳見不得我一個人要去海外出差，所以才硬要跟來的不是嗎！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"고개나 잘 숙이고 있어!","JPN":"いいからちゃんと頭を下げていろよ！","ENG":"Just keep your head down!","TWN":"給我好好低著頭！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......여긴, 보다시피 좀 바쁜데 말이지!","JPN":"……こっちは、見ての通りちょっと忙しくてな！","ENG":"As you can see... We're a little busy here!","TWN":"……我這裡如你們所見，忙得不得了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"수다 떠는 거 다 끝났으면 좀 도와주면 안 될까?","JPN":"おしゃべりが終わったなら、ちょっとばかし手伝ってくれないか？","ENG":"If you're done chatting, could you give us a hand?","TWN":"如果你們已經聊完了，能不能來幫我一點忙啊？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"불평하고 싶진 않지만, 젠장!","JPN":"文句は言いたくないが……ちくしょう！","ENG":"I don’t want to whine or anything... but damn it!","TWN":"雖然我不是很想抱怨，該死！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이쪽엔 카운터 전력이 한 명도 없다고!","JPN":"こっちにはカウンターが1人もいないんだよ！","ENG":"We don’t have a single Counter here!","TWN":"但我這裡連一個可以戰鬥的制裁者都沒有！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"버티는 것도 한계야!","JPN":"このまま耐えるのも限界だ！","ENG":"I don't think we can hold it much longer!","TWN":"我們快要撐不住了！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"사장님! 방금 통신기 쪽에 뭔가 떨어진 것 같은데, 저거 뭐에요?!","JPN":"社長！　今通信機の方に何かが落ちたようですが、あれは何ですか！？","ENG":"Boss! I just saw something fall near the transmission box! What is that?","TWN":"老闆！剛才好像有什麼東西從通信器那邊掉下來了，那是什麼啊？！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐? 어떤 거?","JPN":"うん？　どれどれ？","ENG":"Huh? What are you talking about?","TWN":"什麼？什麼東西？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아, 저거? <color=#ffd34c>여자의 친구</color>네.","JPN":"あれのことか？　<color=#ffd34c>女性の友達</color>だな。","ENG":"Oh, that? It’s the <color=#ffd34c>Lady's Friend</color>.","TWN":"啊，這個啊？是<color=#ffd34c>女人的好朋友</color>呢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"세열 수류탄이라고!! 다들 엎드려!!","JPN":"破片手榴弾ってことだ！！　みんな伏せろ！","ENG":"It’s a frag grenade! Everyone, get down!","TWN":"我是說M67手榴彈！！大家快趴下！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무래도 쉴 여유는 없는 것 같네요. 당장 지원을.......","JPN":"どうも休む暇はなさそうですね。すぐに支援を……","ENG":"Sounds like break time is over. Let’s go help them right away...","TWN":"看來沒有休息的空檔了，立即支援……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"잠깐만.","JPN":"ちょっと待って。","ENG":"Just a moment.","TWN":"等一下。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"왜 그러시죠, 실비아 양.","JPN":"シルビアさん、どうしました？","ENG":"What’s wrong, Sylvia?","TWN":"怎麼了，希爾維亞小姐。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐 느껴지는 거 없어?","JPN":"何か感じない？","ENG":"Don't you smell something fishy?","TWN":"妳沒察覺到什麼嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......뭐가 말이죠?","JPN":"……何をですか？","ENG":"What do you mean?","TWN":"……妳是指？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이건 전형적인 흔들기 전술이라고.","JPN":"これは典型的な揺さぶり戦術よ。","ENG":"This is a typical shake down.","TWN":"這是典型的動搖軍心戰術。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"숫자와 화력의 우위를 기반으로 여기저기 몰아치면서 우릴 지치게 만드는 거야.","JPN":"人数と火力の優勢を見せつけながら、四方八方から追い詰める。それでアタシたちを疲弊させるんだわ。","ENG":"They’re using their superior firepower and numbers to hit us all over the place. They're trying to wear us down.","TWN":"他們仗著兵力與火力的優勢四處發動攻擊，好讓我們疲於奔命。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이렇게 놈들의 파상공세에 끌려 다니기만 하면 끝이 없어.","JPN":"このまま奴らの波状攻撃に振り回されてたら、キリがない。","ENG":"If we let them run us around like this, there’ll be no end to this.","TWN":"如果被這些傢伙的攻勢牽著鼻子走，根本沒完沒了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"우리가 한 장소에 발이 묶인 사이에 로스트 쉽을 빼앗길 수도 있다고!","JPN":"アタシたちが1か所に足止めされている間に、ロストシップを奪われる可能性だってある！","ENG":"They might pin us down in one spot and take the Lost Ship!","TWN":"趁著我們在某個地方陷入交戰時，他們就有可能過來把失落艦船搶走！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"과연...... 모니터만 보고 사는 너드인 줄 알았는데 이런 쪽에도 해박하시네요.","JPN":"なるほど……モニターだけ見て生きるオタクだと思っていたのに、こっち方面にも詳しいんですね。","ENG":"I see... I took you for a computer nerd, but I see you’re also quite the tactician.","TWN":"確實有可能……我原本以為妳是個只會盯著螢幕看的阿宅，沒想到妳在這方面的知識也這麼豐富。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그야 이건 보통 우리가 즐겨 쓰는 전매특허 전술......","JPN":"そりゃ本来あれはアタシたちの専売特許……","ENG":"Oh, it’s just our go-to tactics for-","TWN":"因為那通常是我們喜歡用的專利戰術……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":" 아니, 그게 중요한 게 아니라!","JPN":"ってそれはどうでもよくて！","ENG":" I mean, forget about that!","TWN":"不對，這不重要！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"우선순위를 혼동하면 곤란해.","JPN":"優先順位を間違えられたら困るのよ。","ENG":"We've got to keep our priorities straight.","TWN":"搞錯優先順序的話，我會很困擾的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"의뢰 목표는 어디까지나 <color=#ffd34c>로스트 쉽 확보</color>라고.","JPN":"依頼目標は、あくまでも<color=#ffd34c>ロストシップ確保</color>なんだから。","ENG":"I’m paying you to <color=#ffd34c>secure the Lost Ship</color>.","TWN":"我的委託說到底，都是<color=#ffd34c>確保失落艦船</color>。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"서, 설마 메이슨 씨를...... 버, 버리자는 건가요?","JPN":"ま、まさかメイソンさんを……見捨てようっていうんですか？","ENG":"Y-you don't mean... we should abandon Mr. Mason?","TWN":"妳、妳該不會要我們……拋棄梅森先生吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"냉혹하게 들리겠지만, 내겐 임무가 더 중요해.","JPN":"冷たく聞こえるかもしれないけど、アタシにとっては任務のほうが大事よ。","ENG":"I know it sounds cruel, but the mission is more important to me.","TWN":"這聽起來也許有點冷酷，但對我來說任務更重要。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러니까.......","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"내가 이럴 줄 알았다니까! 하여간 미국 놈들이란, 영화랑 똑같아!","JPN":"いずれこうなると思ってたぜ！　アメリカ野郎め、映画と同じじゃねえか！","ENG":"I knew it! You folks are just like in the movies!","TWN":"我就知道！反正這些美國人都和電影裡演得一模一樣啦！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"너희들만 가.","JPN":"君たちだけ行きなさい。","ENG":"You guys go ahead.","TWN":"你們幾個去幫他吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"항상 자기 이익밖에 모를...... 뭐?","JPN":"いつだって自分の利益のことしか頭にない……えっ？","ENG":"Just a bunch of selfish, conniving sons of- Huh?","TWN":"永遠都只想著自己的利益……什麼？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"실비아 씨?","JPN":"シルビアさん……？","ENG":"Sylvia?","TWN":"希爾維亞小姐？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"말했지? 이건 우리 전매특허라고.","JPN":"さっき言ったでしょ？　あれはアタシたちの専売特許だって。","ENG":"Like I said... This is our go-to move.","TWN":"我不是說了嗎？這是我們的專利。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이럴 때 당황해서 끌려 다니면 그걸로 끝이야.","JPN":"こんなときに慌てて敵のペースに巻き込まれたら、そこで終わりよ。","ENG":"If we panic and let them drag us around, we’re done for.","TWN":"這種時候，只要慌慌張張地被牽著鼻子走就完蛋了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"1급 기밀 사항이라 자세히 말해 줄 순 없지만, 저 로스트 쉽에는 정말 중요한 정보가 들어 있어. 반드시 지켜내야 해.","JPN":"最上級の機密情報だから詳しいことは言えないけど、あのロストシップには、本当に重要な情報が隠されているの。だから、必ず守り抜かないと。","ENG":"I can’t share the details since it’s Top Secret, but there’s really important information sitting in that Lost Ship. I've got to keep it secure, no matter what.","TWN":"因為這是1級機密事項，所以我沒辦法告訴妳們詳細內容，但這艘失落艦船真的有非常重要的情報，我一定得守住它。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러니까 놈들이 양동작전으로 로스트 쉽을 탈취하지 못하도록 내가 막고 있겠어.","JPN":"だから、奴らが陽動作戦でロストシップを奪い取ることがないように、アタシが阻止してみせる。","ENG":"That’s why I’ll hold them off so they won’t steal the Lost Ship through a feint attack.","TWN":"所以那些傢伙想要用佯動作戰，奪取失落艦船的詭計就由我來阻止。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"어...... 그건...... 야! 그...... 그건 너무 위험하잖아!","JPN":"え……それは……おい！　そ……それは危険すぎるじゃねえか！","ENG":"Um... But... Come on! That’s... way too dangerous!","TWN":"啊……這個……喂！這、這個太危險了吧！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"걱정 마. 네 말대로 미국인은 계산에 밝으니까.","JPN":"心配無用よ。君の言うとおり、アメリカ人は計算に長けてるから。","ENG":"Don't worry. I've already calculated all possible outcomes.","TWN":"不用擔心。就跟妳說得一樣，美國人很擅長算計。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"내가 뭐 자살 취미라도 있어서 이러는 것 같아?","JPN":"自殺行為が趣味だからこうするとでも思ってるの！？","ENG":"Hey, I’m not suicidal or anything.","TWN":"我看起來像是有什麼自殺嗜好才做這種事的嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"놈들의 목표도 우리와 같다면, 아마 그쪽에 모인 건 시간벌이를 위한 보조 전력일 거야.","JPN":"奴らの目標がアタシたちと同じなら、たぶんそっちに集まったのはただの時間稼ぎの戦力だと思う。","ENG":"If their objectives are the same as ours, then the troops they've committed are probably just auxiliaries buying time.","TWN":"如果那些傢伙的目標跟我們一樣，那聚集在那邊的，大概就是爭取時間的佯攻部隊。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러니까 우리는 전력을 한쪽에 최대한 집중해서 빠르게 메이슨 아저씨 쪽을 구출한 다음 로스트 쉽으로 합류하면 돼.","JPN":"だから、アタシはできるだけ片方に戦力を集中させて、メイソンさんを早急に救出する。それからロストシップで合流すればいいのよ。","ENG":"That’s why we’ve got to focus our effort on one side and extract Mr. Mason ASAP, then link up at the Lost Ship.","TWN":"所以我們的戰術就是將戰力集中在一處，迅速救出梅森大叔他們後，在失落艦船處會合。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"위험하긴 하지만 승산은 충분히 있어.","JPN":"危険だけど、勝算は十分にある。","ENG":"It’s risky, but we’ve got a shot.","TWN":"雖然很危險，但我們還是有十足的勝算。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"어...... 그, 그런가?","JPN":"あ……そ、そうなのか？","ENG":"Um... I-is that right?","TWN":"啊……是、是這樣嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"너무 위험해요. 그럼 차라리 우리도 두 명씩 나눠서 같이 방어를.......","JPN":"でも、危険すぎます。だったら、私たちも2人ずつ分かれて、一緒に防御を……","ENG":"It’s way too risky. Maybe we should split up and defend the area...","TWN":"那樣太危險了，不然我們乾脆也分成兩隊來防禦……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아까 뭘 들은 거야? 이건 숫자와 화력이 높은 쪽이 이기는 게임이야.","JPN":"さっきの話聞いてた？　これは人数と火力で上回った方が勝つゲームなの。","ENG":"Did I stutter? Whoever has the superior firepower and numbers is going to win this game.","TWN":"我剛才的話妳都聽到哪去了？這是一場誰的數量和火力高，誰就會贏的遊戲啊。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"안 그래도 부족한 전력을 더 나눴다간 죽도 밥도 안 된다고!","JPN":"元から足りない戦力をさらに分けたりなんかしたら、何にもならないのよ！","ENG":"We’re already outnumbered as it is. If we split up, we’ll get nowhere!","TWN":"而且我們的兵力本來就不夠了，再分下去就什麼都不用幹了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무래도 실비아 양의 말이 맞는 것 같군요.","JPN":"どうやらシルビアさんの言っていることが正しいようですね。","ENG":"I’m afraid Sylvia is right.","TWN":"希爾維亞小姐說得沒錯。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"명령입니다. 알트 소대는 지금 즉시 메이슨 용병단을 구원하러 가세요.","JPN":"命令です。アルト小隊は、今すぐメイソン傭兵団の救援に向かってください。","ENG":"This is an order. ALT Squad, go extract Mason's team immediately.","TWN":"這是命令，阿爾特小隊現在立刻出發，去營救梅森傭兵團。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하지만 부사장님.......","JPN":"しかし、副社長……","ENG":"But ma’am...","TWN":"但是副總……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 로스트 쉽 방어는 실비아 양과 제가 맡도록 하겠습니다.","JPN":"それから、ロストシップの防御は、シルビアさんと私が担当します。","ENG":"I’ll keep the Lost Ship secure alongside Sylvia.","TWN":"失落艦船的防禦就交給我跟希爾維亞小姐。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마, 뭔 소리야?","JPN":"おばさん、何言ってるの？","ENG":"Are you serious, lady?","TWN":"大嬸，妳在說什麼啊？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"안 그래도 힘들어 죽겠는데 아줌마 뒤치다꺼리까지 해 줄 여유가 있을 것 같아?!","JPN":"そうじゃなくても大変なのに、おばさんの面倒までみろって！？","ENG":"I've got enough on my plate as it is. I don’t have time to cover your old butt!","TWN":"我已經夠嗆了，可沒有閒工夫去照顧妳啊？！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그건 걱정 마시죠.","JPN":"それは心配無用です。","ENG":"Don't worry about that.","TWN":"不用擔心。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아까도 말씀드렸지만, 제 몸 하나 건사하는 데 새파란 후배들 발목을 잡아야 할 만큼 말랑말랑한 인생을 살아오진 않았습니다.","JPN":"さっきも言いましたが、自分1人守れず後輩の足を引っ張るほど、ヤワな人生は送ってきませんでしたから。","ENG":"Like I said, I've been through enough FUBAR situations that I can handle myself without needing you youngsters to protect me.","TWN":"我剛才也說過了，我可沒有柔弱到得抱著後輩大腿才能活下去。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 비전투 요원인 제가 따라가게 되면 오히려 알트 소대의 기동성에 방해만 될 테니까요.","JPN":"それに非戦闘隊員の私が同行しても、かえってアルト小隊の機動力を落とすだけだと思います。","ENG":"Besides, a “non-combatant” like me would only slow down the ALT Squad if I tagged along.","TWN":"而且我一個非戰鬥要員，如果跟著阿爾特小隊走，反而會妨礙她們的機動性。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"누구처럼 고집불통이네. 마음대로 해, 아줌마.","JPN":"誰かさんみたいに頑固者ね。好きにすれば、おばさん。","ENG":"You're as stubborn as someone I know back home. Suit your self, lady.","TWN":"和某人一樣頑固呢，隨便妳吧，大嬸。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"결정됐군요. 시간이 없어요. 서두릅시다.","JPN":"これで決まりですね。時間がありません、急ぎましょう。","ENG":"Then it’s decided. There’s no time. Hurry.","TWN":"那就這麼決定了。沒時間了，你們快去吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"잘 부탁해요, 서윤 양.","JPN":"シズカさん、よろしく頼みますね。","ENG":"I’m counting on you, Seo Yoon.","TWN":"拜託妳了，徐芸小姐。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제가 살아 있어야 다음 달 급여도 드릴 수 있을 테니까요.","JPN":"私が生きていないと来月の給料もあげられませんからね。","ENG":"You’ll need to keep me alive if you want that paycheck next month.","TWN":"畢竟只有我活著，才有辦法幫大家發下個月的薪水。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......알겠습니다. 안정적인 직장을 위해 최선을 다해 볼게요.","JPN":"……了解しました。職場の平和のために、最善をつくします。","ENG":"Understood. I’ll try my best to keep my salary secure.","TWN":"……我明白了。為了我們安穩的職場，我會盡全力的。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"몸조심하세요. 부사장님, 실비아 씨.","JPN":"気をつけてくださいね。副社長とシルビアさん。","ENG":"Please take care. Ma’am. Sylvia.","TWN":"請你們保重。副總，希爾維亞小姐。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};